  6→interface PointsInputProps extends SDUIComponentProps {
  7→  label: string;
  8→  placeholder?: string;
  9→  keyboardType?: string;
 10→  textRight?: string;
 11→  textError?: string;
 12→  mb?: string;
 13→  contextKey?: string;
 14→  validation?: SDUIValidation;
 15→}
 16→
 17→function buildValidationContext(
 18→  context: SDUIContext,
 19→  contextKey: string | undefined,
 20→  value: string,
 21→): SDUIContext {
 22→  if (!contextKey) return context;
 23→
 24→  const segments = contextKey.split('.');
 25→  if (segments.length === 1) {
 26→    return { ...context, [segments[0]]: parseFloat(value) || 0 };
 27→  }
 28→
 29→  const [root, ...rest] = segments;
 30→  const parent = (context[root] ?? {}) as SDUIContext;
 31→  let nested: SDUIContext = { ...parent };
 32→  let ref = nested;
 33→  for (let i = 0; i < rest.length - 1; i++) {
 34→    const child = { ...((ref[rest[i]] ?? {}) as SDUIContext) };
 35→    ref[rest[i]] = child;
 36→    ref = child;
 37→  }
 38→  ref[rest[rest.length - 1]] = parseFloat(value) || 0;
 39→
 40→  return { ...context, [root]: nested };
 41→}
 42→
 43→export default function PointsInputAdapter({
 44→  props,
 45→  context,
 46→}: {
 47→  props: PointsInputProps;
 48→  context: SDUIContext;
 49→}) {
 50→  const {
 51→    label,
 52→    placeholder = '0',
 53→    keyboardType = 'number-pad',
 54→    textRight,
 55→    textError,
 56→    mb,
 57→    contextKey,
 58→    validation,
 59→  } = props;
 60→
 61→  const [value, setValue] = useState('');
 62→  const [validationError, setValidationError] = useState<string | null>(null);
 63→  const [touched, setTouched] = useState(false);
 64→
 65→  const runValidation = useCallback(
 66→    (text: string) => {
 67→      if (!validation) return;
 68→      const ctx = buildValidationContext(context, contextKey, text);
 69→      setValidationError(validateField(validation, ctx));
 70→    },
 71→    [validation, context, contextKey],
 72→  );
 73→
 74→  const handleChange = useCallback(
 75→    (text: string) => {
 76→      setValue(text);
 77→      if (touched) runValidation(text);
 78→    },
 79→    [touched, runValidation],
 80→  );
 81→
 82→  const handleBlur = useCallback(() => {
 83→    setTouched(true);
 84→    runValidation(value);
 85→  }, [value, runValidation]);
 86→
 87→  const handleUseAll = useCallback(() => {
 88→    // In a real implementation, this would read from context/store
 89→  }, []);
 90→
 91→  const displayError = validationError ?? (textError ? String(textError) : undefined);
 92→
 93→  return (
 94→    <InputBox
 95→      label={String(label)}
 96→      placeholder={String(placeholder)}
 97→      showLabel
 98→      keyboardType={keyboardType}
 99→      value={value}
100→      onChangeText={handleChange}
101→      onBlur={handleBlur}
102→      error={!!validationError}
103→      textError={displayError}
104→      textRight={textRight ? String(textRight) : undefined}
105→      onPressTextRight={textRight ? handleUseAll : undefined}
106→      mb={mb}
107→    />
108→  );
109→}
